def gen(rng, size):
    vocab = ['alpha', 'beta', 'gamma', 'delta', 'epsilon', 'zeta', 'eta', 'theta']
    def make_sentence(n):
        words = [rng.choice(vocab) for _ in range(n)]
        return ' '.join(words)
    n1 = rng.randint(1, max(1, size // 2))
    n2 = rng.randint(1, max(1, size // 2))
    return [make_sentence(n1), make_sentence(n2)]

