class Solution:
    def uncommonFromSentences(self, s1: str, s2: str):
        freq = {}
        for w in (s1 + ' ' + s2).split():
            freq[w] = freq.get(w, 0) + 1
        result = []
        for w, c in freq.items():
            if c == 1:
                result.append(w)
        return result

